const wd = "[REDACTED_LOCAL_PATH]";
const tp = wd + "/work/v1_2_1_taskpack/v1.2.1_四线16Stage质量收敛升级_TaskPack";
const [files, handoffs, mem] = await Promise.all([
  tools.exec_command({
    cmd: "find . -maxdepth 3 -type f ! -path '*/raw/*' ! -path '*/session_history/*' -print | LC_ALL=C sort",
    workdir: tp,
    yield_time_ms: 10000,
    max_output_tokens: 20000
