  tools.exec_command({
    cmd: "find . -type f -name HANDOFF.md ! -path '*/raw/*' ! -path '*/session_history/*' -print",
    workdir: wd,
    yield_time_ms: 10000,
    max_output_tokens: 10000
  }),
  tools.exec_command({
    cmd: "rg -n -i -m 40 'v1\\.2\\.1|四线16Stage|cloudflare|linzehomehub|S02|EEI|OpenAIDatabase' [REDACTED_LOCAL_PATH]",
    workdir: wd,
    yield_time_ms: 10000,
    max_output_tokens: 10000
  })
]);
text("FILES\n" + files.output);
text("HANDOFFS\n" + handoffs.output);
text("MEMORY_HITS\n" + mem.output);

const wd = "[REDACTED_LOCAL_PATH]";
const tp = wd + "/work/v1_2_1_taskpack/v1.2.1_四线16Stage质量收敛升级_TaskPack";
