  workdir: tp,
  yield_time_ms: 10000,
  max_output_tokens: 20000
});
text(r.output);

const tp = "[REDACTED_LOCAL_PATH]";
const [readme, intro, hits] = await Promise.all([
  tools.exec_command({cmd:"nl -ba README_先读我.md",workdir:tp,yield_time_ms:10000,max_output_tokens:12000}),
  tools.exec_command({cmd:"nl -ba 01_Codex整合任务包_v1.2.1.md",workdir:tp,yield_time_ms:10000,max_output_tokens:30000}),
  tools.exec_command({cmd:"rg -n '^#|^##|^###|S02|Review|禁止|不得|不允许|只读|Stop|STOP|stop' 02_Roadmap_16Stage_Phase_Task.md",workdir:tp,yield_time_ms:10000,max_output_tokens:30000})
]);
