text("INTRO\n"+intro.output);
text("ROADMAP_HITS\n"+hits.output);

const r = await tools.exec_command({
  cmd: "nl -ba 02_Roadmap_16Stage_Phase_Task.md | sed -n '1,210p'",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 10000,
  max_output_tokens: 45000
});
text(r.output);

const r = await tools.exec_command({
  cmd: "jq 'keys' machine/roadmap.json && jq '.stages | length' machine/roadmap.json && jq '.stages[] | select((.id // .stage_id // .code)==\"S02\")' machine/roadmap.json",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 10000,
  max_output_tokens: 50000
});
text(r.output);

