const r = await tools.exec_command({
  cmd: "rg -n '\"id\": \"S02\"|\"id\": \"S03\"' machine/roadmap.json",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 10000,
  max_output_tokens: 5000
});
text(r.output);

const r = await tools.exec_command({
  cmd: "nl -ba machine/roadmap.json | sed -n '112,235p'",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 10000,
  max_output_tokens: 35000
});
text(r.output);

const [gates, manifest, report] = await Promise.all([
  tools.exec_command({cmd:"nl -ba machine/stage_gate_matrix.csv",workdir:"[REDACTED_LOCAL_PATH]",yield_time_ms:10000,max_output_tokens:10000}),
  tools.exec_command({cmd:"nl -ba PACK_MANIFEST.json",workdir:"[REDACTED_LOCAL_PATH]",yield_time_ms:10000,max_output_tokens:30000}),
  tools.exec_command({cmd:"nl -ba machine/package_validation_report.json",workdir:"[REDACTED_LOCAL_PATH]",yield_time_ms:10000,max_output_tokens:30000})
]);
text("GATES\n"+gates.output);
text("MANIFEST\n"+manifest.output);
text("VALIDATION_REPORT\n"+report.output);

const [pol, schema, scope, acc] = await Promise.all([
  tools.exec_command({cmd:"nl -ba machine/cleanup_policy.json",workdir:"[REDACTED_LOCAL_PATH]",yield_time_ms:10000,max_output_tokens:12000}),
  tools.exec_command({cmd:"nl -ba machine/deletion_candidate_schema.json",workdir:"[REDACTED_LOCAL_PATH]",yield_time_ms:10000,max_output_tokens:15000}),
  tools.exec_command({cmd:"rg -n -i 'S02|raw|session_history|read|write|tracked|entire|全仓|只读|仓库' machine/file_scope_manifest.json",workdir:"[REDACTED_LOCAL_PATH]",yield_time_ms:10000,max_output_tokens:12000}),
  tools.exec_command({cmd:"rg -n '^S02|,S02,' machine/acceptance_matrix.csv",workdir:"[REDACTED_LOCAL_PATH]",yield_time_ms:10000,max_output_tokens:15000})
]);
text("CLEANUP_POLICY\n"+pol.output);
text("CANDIDATE_SCHEMA\n"+schema.output);
text("FILE_SCOPE_HITS\n"+scope.output);
text("ACCEPTANCE_HITS\n"+acc.output);

const r = await tools.exec_command({
  cmd: "nl -ba machine/file_scope_manifest.json | sed -n '1,45p'",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 10000,
  max_output_tokens: 12000
});
text(r.output);

const r = await tools.exec_command({
  cmd: "rg -n -i 'S02[^\\n]*(Review|复审)|(?:Review|复审)[^\\n]*S02|S02-R[0-9]|review gate|审查' . -g '!raw/**' -g '!session_history/**'",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 10000,
  max_output_tokens: 20000
});
text(r.output || "(no matches)");

const tp="[REDACTED_LOCAL_PATH]";
const [a,b,c]=await Promise.all([
  tools.exec_command({cmd:"nl -ba 04_需求冻结与优先级.md",workdir:tp,yield_time_ms:10000,max_output_tokens:30000}),
  tools.exec_command({cmd:"nl -ba 06_全仓清理与真相源收敛规范.md",workdir:tp,yield_time_ms:10000,max_output_tokens:20000}),
  tools.exec_command({cmd:"nl -ba 10_开发门禁停止回滚与发布协议.md",workdir:tp,yield_time_ms:10000,max_output_tokens:20000})
]);
text("FREEZE\n"+a.output);
text("CLEANUP_SPEC\n"+b.output);
text("GATE_SPEC\n"+c.output);

const r = await tools.exec_command({
  cmd: "shasum -a 256 README_先读我.md 01_Codex整合任务包_v1.2.1.md 02_Roadmap_16Stage_Phase_Task.md 04_需求冻结与优先级.md 06_全仓清理与真相源收敛规范.md 10_开发门禁停止回滚与发布协议.md machine/roadmap.json machine/stage_gate_matrix.csv machine/acceptance_matrix.csv machine/file_scope_manifest.json machine/cleanup_policy.json machine/deletion_candidate_schema.json machine/package_validation_report.json",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 10000,
  max_output_tokens: 12000
});
text(r.output);

const r = await tools.exec_command({
  cmd: "nl -ba machine/requirements_traceability.csv | sed -n '1,35p' && nl -ba machine/requirements_freeze.json | sed -n '1,85p'",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 10000,
  max_output_tokens: 25000
});
text(r.output);
